import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
  const [plots, setPlots] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5001/api/plots')
      .then(res => setPlots(res.data))
      .catch(err => console.error(err));
  }, []);

  const [name, setName] = useState('');
  const addPlot = async () => {
    const res = await axios.post('http://localhost:5001/api/plots', {
      name,
      size: "10x10"
    });
    setPlots([...plots, res.data]);
  };

  const deletePlot = async (id) => {
    await axios.delete(`http://localhost:5001/api/plots/${id}`);
    setPlots(plots.filter(plot => plot._id !== id));
  };

  const updatePlot = async (id) => {
    const res = await axios.put(`http://localhost:5001/api/plots/${id}`, {
      status: "Occupied"
    });
    setPlots(plots.map(p => p._id === id ? res.data : p));
  };


  return (
    <div>
      <input 
  placeholder="Enter plot name"
  onChange={(e) => setName(e.target.value)} 
/>
<button onClick={addPlot}>Add Plot</button>
      <h1>Garden Plots</h1>
      {plots.map(plot => (
        <div key={plot._id}>
          {plot.name} - {plot.status}

          <button onClick={() => deletePlot(plot._id)}>Delete </button>
          <button onClick={() => updatePlot(plot._id)}>Mark Occupied</button>
        </div>
      ))}
    </div>
  );
}

export default App;
